<?php
require_once __DIR__.'/../config/db.php';header('Content-Type: application/json');header('X-Frame-Options: DENY');header('X-Content-Type-Options: nosniff');header('Referrer-Policy: strict-origin-when-cross-origin');
function input(){return json_decode(file_get_contents('php://input'),true)?:$_POST;}function out($d,$s=200){http_response_code($s);echo json_encode($d);exit;}function clean($v){return is_string($v)?trim(strip_tags($v)):$v;}
function jwt($uid){$c=require __DIR__.'/../config/config.php';$h=rtrim(strtr(base64_encode(json_encode(['alg'=>'HS256','typ'=>'JWT'])),'+/','-_'),'=');$p=rtrim(strtr(base64_encode(json_encode(['sub'=>$uid,'exp'=>time()+604800])),'+/','-_'),'=');$sig=rtrim(strtr(base64_encode(hash_hmac('sha256',"$h.$p",$c['jwt_secret'],true)),'+/','-_'),'=');return "$h.$p.$sig";}
function user(){ $hdr=$_SERVER['HTTP_AUTHORIZATION']??''; if(!preg_match('/Bearer\s+(.*)$/',$hdr,$m))out(['error'=>'Unauthorized'],401);$c=require __DIR__.'/../config/config.php';[$h,$p,$s]=explode('.',$m[1]);$sig=rtrim(strtr(base64_encode(hash_hmac('sha256',"$h.$p",$c['jwt_secret'],true)),'+/','-_'),'=');if(!hash_equals($sig,$s))out(['error'=>'Bad token'],401);$pay=json_decode(base64_decode(strtr($p,'-_','+/')),true);if(($pay['exp']??0)<time())out(['error'=>'Expired'],401);$st=db()->prepare('select * from users where id=? and status="active"');$st->execute([$pay['sub']]);return $st->fetch()?:out(['error'=>'User not found'],401);}
function log_api($path,$status,$msg=''){try{$st=db()->prepare('insert into api_logs(path,status,message,created_at)values(?,?,?,now())');$st->execute([$path,$status,$msg]);}catch(Throwable $e){}}
